(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["learn2"],{"480e":function(r,n,e){"use strict";e.r(n);var s=function(){var r=this,n=r.$createElement,s=r._self._c||n;return s("markdown",{attrs:{source:e("95ea")}})},t=[],o=e("2877"),u={},c=Object(o["a"])(u,s,t,!1,null,null,null);c.options.__file="expressapi.vue";n["default"]=c.exports},"95ea":function(r,n){r.exports="### 范例\r\n查询商品列表数据\r\n```js\r\nrouter.get(\"/list\", function (req, res, next) {\r\n  // 获取当前页 page\r\n  let page = parseInt(req.param(\"page\"));\r\n  // 获取每页条数 pageSize\r\n  let pageSize = parseInt(req.param(\"pageSize\"));\r\n  // 获取价格等级priceLevel\r\n  let priceLevel = req.param(\"priceLevel\");\r\n  //  获取排序sort\r\n  let sort = req.param(\"sort\");\r\n  //  算出当前页要跳过多少条数据\r\n  let skip = (page - 1) * pageSize;\r\n  // 根据priceLevel获取价格区间\r\n  var priceGt = '',  \r\n    priceLte = '';  \r\n  let params = {};\r\n  if (priceLevel != 'all') {\r\n    switch (priceLevel) {\r\n      case '0':\r\n        priceGt = 0;\r\n        priceLte = 100;\r\n        break;\r\n      case '1':\r\n        priceGt = 100;\r\n        priceLte = 500;\r\n        break;\r\n      case '2':\r\n        priceGt = 500;\r\n        priceLte = 1000;\r\n        break;\r\n      case '3':\r\n        priceGt = 1000;\r\n        priceLte = 5000;\r\n        break;\r\n    }\r\n    // 设置查询价格参数\r\n    params = {\r\n      salePrice: {\r\n        $gt: priceGt,\r\n        $lte: priceLte\r\n      }\r\n    }\r\n  }\r\n  // 查询sql\r\n  let goodsModel = Goods.find(params).skip(skip).limit(pageSize);\r\n  // 排序\r\n  goodsModel.sort({\r\n    'salePrice': sort\r\n  });\r\n  // 获取数据\r\n  goodsModel.exec(function (err, doc) {\r\n    if (err) {\r\n      res.json({\r\n        status: '1',\r\n        msg: err.message\r\n      });\r\n    } else {\r\n      res.json({\r\n        status: '0',\r\n        msg: '',\r\n        result: {\r\n          count: doc.length,\r\n          list: doc\r\n        }\r\n      });\r\n    }\r\n  })\r\n});\r\n```\r\n加入到购物车\r\n```js\r\nrouter.post(\"/addCart\", function (req, res, next) {\r\n  // 从cookie获取用户的 id\r\n  const userId = req.cookies.userId;\r\n  // 获取产品id\r\n  const productId = req.body.productId;\r\n  // 获取user的 model\r\n  const User = require('../models/user');\r\n\r\n  // 获取用户信息\r\n  User.findOne({\r\n    userId: userId\r\n  }, function (err, userDoc) {\r\n    if (err) {  // 获取失败\r\n      res.json({\r\n        status: \"1\",\r\n        msg: err.message\r\n      })\r\n    } else { // 获取成功\r\n      // 用户信息存在\r\n      if (userDoc) {\r\n        // 该产品是否在购物车中，在购物车中的话 ,productNum++\r\n        var goodsItem = '';\r\n        userDoc.cartList.forEach(function (item) {\r\n          if (item.productId == productId) {\r\n            goodsItem = item;\r\n            item.productNum++;\r\n          }\r\n        });\r\n        // 在购物车中\r\n        if (goodsItem) {\r\n          userDoc.save(function (err2, doc2) {\r\n            if (err2) {\r\n              res.json({\r\n                status: \"1\",\r\n                msg: err2.message\r\n              })\r\n            } else {\r\n              res.json({\r\n                status: '0',\r\n                msg: '',\r\n                result: 'suc'\r\n              })\r\n            }\r\n          })\r\n        // 不在购物车中\r\n        } else {\r\n          // 获取该产品的信息\r\n          Goods.findOne({\r\n            productId: productId\r\n          }, function (err1, doc) {\r\n            // 获取失败\r\n            if (err1) {\r\n              res.json({\r\n                status: \"1\",\r\n                msg: err1.message\r\n              })\r\n            // 获取成功\r\n            } else {\r\n              if (doc) {\r\n                //将该产品添加到购物车userDoc.cartList中\r\n                userDoc.cartList.push({\r\n                  \"productId\": doc.productId,\r\n                  \"productName\": doc.productName,\r\n                  \"salePrice\": doc.salePrice,\r\n                  \"productImage\": doc.productImage,\r\n                  \"productNum\": 1,\r\n                  \"checked\": 1\r\n                });\r\n                // 保存userDoc\r\n                userDoc.save(function (err2, doc2) {\r\n                  // 保存成功\r\n                  if (err2) {\r\n                    res.json({\r\n                      status: \"1\",\r\n                      msg: err2.message\r\n                    })\r\n                  // 保存失败\r\n                  } else {\r\n                    res.json({\r\n                      status: '0',\r\n                      msg: '',\r\n                      result: 'suc'\r\n                    })\r\n                  }\r\n                })\r\n              }\r\n            }\r\n          });\r\n        }\r\n      // 用户信息不存在\r\n      }else{ \r\n        res.json({\r\n          status: \"1\",\r\n          msg: '用户信息不存在'\r\n        })\r\n      }\r\n    }\r\n  })\r\n});\r\n```\r\n\r\n用户登录\r\n```js\r\nrouter.post(\"/login\", function (req, res, next) {\r\n  // 获取用户名和密码\r\n  var param = {\r\n    userName: req.body.userName,\r\n    userPwd: req.body.userPwd\r\n  }\r\n  // 查询是否存在改用户\r\n  User.findOne(param, function (err, doc) {\r\n    // 不存在\r\n    if (err) {\r\n      res.json({\r\n        status: \"1\",\r\n        msg: err.message\r\n      });\r\n    // 存在\r\n    } else {\r\n      if (doc) {\r\n        // 将userId 写入到cookie里\r\n        res.cookie(\"userId\", doc.userId, {\r\n          path: '/',\r\n          maxAge: 1000 * 60 * 60\r\n        });\r\n        // 将userName 写入到cookie里\r\n        res.cookie(\"userName\", doc.userName, {\r\n          path: '/',\r\n          maxAge: 1000 * 60 * 60\r\n        });\r\n        //req.session.user = doc;\r\n        // 登录成功\r\n        res.json({\r\n          status: '0',\r\n          msg: '',\r\n          result: {\r\n            userName: doc.userName\r\n          }\r\n        });\r\n      } else {\r\n        // 登录失败\r\n        res.json({\r\n          status: '1',\r\n          msg: '账户密码错误',\r\n          result: ''\r\n        });\r\n      }\r\n    }\r\n  });\r\n});\r\n```\r\n\r\n是否登录\r\n```js\r\nrouter.get(\"/checkLogin\", function (req, res, next) {\r\n  if (req.cookies.userId) {\r\n    res.json({\r\n      status: '0',\r\n      msg: '',\r\n      result: req.cookies.userName || ''\r\n    });\r\n  } else {\r\n    res.json({\r\n      status: '1',\r\n      msg: '未登录',\r\n      result: ''\r\n    });\r\n  }\r\n});\r\n```\r\n\r\n登出接口\r\n```js\r\nrouter.post(\"/logout\", function (req, res, next) {\r\n  // 清除cookie\r\n  res.cookie(\"userId\", \"\", {\r\n    path: \"/\",\r\n    maxAge: -1\r\n  });\r\n  res.json({\r\n    status: \"0\",\r\n    msg: '',\r\n    result: ''\r\n  })\r\n});\r\n```\r\n登录拦截\r\n```js\r\napp.use(function (req, res, next) {\r\n  if (req.cookies.userId ||req.originalUrl == '/users/login' || req.originalUrl == '/users/logout' || req.path ==\"/goods/list\") {\r\n    next();\r\n  } else {\r\n      res.json({\r\n        status: '10001',\r\n        msg: '当前未登录',\r\n        result: ''\r\n      });\r\n    }\r\n  }\r\n});\r\n```\r\n\r\n查询当前用户的购物车数据\r\n```js\r\nrouter.get(\"/cartList\", function (req, res, next) {\r\n  var userId = req.cookies.userId;\r\n  User.findOne({\r\n    userId: userId\r\n  }, function (err, doc) {\r\n    if (err) {\r\n      res.json({\r\n        status: '1',\r\n        msg: err.message,\r\n        result: ''\r\n      });\r\n    } else {\r\n      if (doc) {\r\n        res.json({\r\n          status: '0',\r\n          msg: '',\r\n          result: doc.cartList\r\n        });\r\n      }\r\n    }\r\n  });\r\n});\r\n```\r\n\r\n购物车删除\r\n```js\r\nrouter.post(\"/cartDel\", function (req, res, next) {\r\n  var userId = req.cookies.userId,\r\n    productId = req.body.productId;\r\n  User.update({\r\n    userId: userId\r\n  }, {\r\n    $pull: {\r\n      'cartList': {\r\n        'productId': productId\r\n      }\r\n    }\r\n  }, function (err, doc) {\r\n    if (err) {\r\n      res.json({\r\n        status: '1',\r\n        msg: err.message,\r\n        result: ''\r\n      });\r\n    } else {\r\n      res.json({\r\n        status: '0',\r\n        msg: '',\r\n        result: 'suc'\r\n      });\r\n    }\r\n  });\r\n});\r\n```\r\n修改商品数量\r\n```js\r\nrouter.post(\"/cartEdit\", function (req, res, next) {\r\n  var userId = req.cookies.userId,\r\n    productId = req.body.productId,\r\n    productNum = req.body.productNum,\r\n    checked = req.body.checked;\r\n  User.update({\r\n    \"userId\": userId,\r\n    \"cartList.productId\": productId\r\n  }, {\r\n    \"cartList.$.productNum\": productNum,\r\n    \"cartList.$.checked\": checked,\r\n  }, function (err, doc) {\r\n    if (err) {\r\n      res.json({\r\n        status: '1',\r\n        msg: err.message,\r\n        result: ''\r\n      });\r\n    } else {\r\n      res.json({\r\n        status: '0',\r\n        msg: '',\r\n        result: 'suc'\r\n      });\r\n    }\r\n  })\r\n});\r\n```\r\n\r\n购物车全选\r\n```js\r\nrouter.post(\"/editCheckAll\", function (req, res, next) {\r\n  var userId = req.cookies.userId,\r\n    checkAll = req.body.checkAll ? '1' : '0';\r\n  User.findOne({\r\n    userId: userId\r\n  }, function (err, user) {\r\n    if (err) {\r\n      res.json({\r\n        status: '1',\r\n        msg: err.message,\r\n        result: ''\r\n      });\r\n    } else {\r\n      if (user) {\r\n        user.cartList.forEach((item) => {\r\n          item.checked = checkAll;\r\n        })\r\n        user.save(function (err1, doc) {\r\n          if (err1) {\r\n            res.json({\r\n              status: '1',\r\n              msg: err1.message,\r\n              result: ''\r\n            });\r\n          } else {\r\n            res.json({\r\n              status: '0',\r\n              msg: '',\r\n              result: 'suc'\r\n            });\r\n          }\r\n        })\r\n      }\r\n    }\r\n  });\r\n});\r\n```"}}]);